  "dependencies": {
    "@anthropic-ai/claude-agent-sdk": "^0.1.30"
  },
  "engines": {
    "node": ">=18.0.0"
  },
  "keywords": [
    "claude",
    "docker",
    "sandbox",
    "ai",
    "agent"
  ],
